sys_script_include.script:
var GeminiAIRecommendation = Class.create();

GeminiAIRecommendation.prototype = {

    initialize: function() {},

    getRecommendation: function(customerSysId) {

        // Get customer record
       var customer = new GlideRecord('x_2048400_churn_1_customer_profile_table');

        if (!customer.get(customerSysId)) {
            return "Customer not found";
        }

        // Build AI prompt
        var prompt =
            "You are an AI customer retention expert.\n\n" +

            "Analyze this customer and provide 3 retention recommendations.\n\n" +

            "Company: " + customer.u_company_name + "\n" +
            "Risk Score: " + customer.u_churn_risk_score + "\n" +
            "Risk Category: " + customer.u_risk_category + "\n" +
            "Open Tickets: " + customer.u_open_tickets + "\n" +
            "NPS Score: " + customer.u_nps_score + "\n\n" +

            "Provide short professional recommendations.";

        // REST message
        var rm = new sn_ws.RESTMessageV2();

        rm.setEndpoint(
            'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash-lite:generateContent?key=' +
            gs.getProperty('x_2048400_churn_1.ChurnPredictionAI')
        );

        rm.setHttpMethod('POST');

        rm.setRequestHeader(
            'Content-Type',
            'application/json'
        );

        // Request body
        var requestBody = {
            contents: [
                {
                    parts: [
                        {
                            text: prompt
                        }
                    ]
                }
            ]
        };

        rm.setRequestBody(JSON.stringify(requestBody));

        // Execute request
        var response = rm.execute();

        // Parse response
        var responseBody = JSON.parse(response.getBody());

// Debug full response
// gs.info(JSON.stringify(responseBody));

// Safe response handling
if (
    responseBody.candidates &&
    responseBody.candidates.length > 0 &&
    responseBody.candidates[0].content &&
    responseBody.candidates[0].content.parts &&
    responseBody.candidates[0].content.parts.length > 0
) {

    return responseBody.candidates[0].content.parts[0].text;
}
else {

   return "1. Schedule customer success onboarding session.\n" +
       "2. Offer renewal discount for retention.\n" +
       "3. Escalate unresolved support tickets to senior support team.";
}
    },

    type: 'GeminiAIRecommendation'
};
